/* ============================================================
   Utilidades de geometría: Catmull-Rom, normalización, prepared
   ============================================================ */

function catmullRomClosed(points, samplesPerSeg = 12, alpha = 0.5) {
  const n = points.length;
  const out = [];

  function tj(ti, pi, pj) {
    const dx = pj[0] - pi[0];
    const dy = pj[1] - pi[1];
    return ti + Math.pow(dx * dx + dy * dy, alpha * 0.5);
  }
  function lerpPt(a, b, t) {
    return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t];
  }

  for (let i = 0; i < n; i++) {
    const p0 = points[(i - 1 + n) % n];
    const p1 = points[i];
    const p2 = points[(i + 1) % n];
    const p3 = points[(i + 2) % n];

    const t0 = 0;
    const t1 = tj(t0, p0, p1) || 1e-6;
    const t2 = tj(t1, p1, p2) || (t1 + 1e-6);
    const t3 = tj(t2, p2, p3) || (t2 + 1e-6);

    for (let j = 0; j < samplesPerSeg; j++) {
      const t = t1 + (t2 - t1) * (j / samplesPerSeg);
      const A1 = lerpPt(p0, p1, (t - t0) / (t1 - t0));
      const A2 = lerpPt(p1, p2, (t - t1) / (t2 - t1));
      const A3 = lerpPt(p2, p3, (t - t2) / (t3 - t2));
      const B1 = lerpPt(A1, A2, (t - t0) / (t2 - t0));
      const B2 = lerpPt(A2, A3, (t - t1) / (t3 - t1));
      const C  = lerpPt(B1, B2, (t - t1) / (t2 - t1));
      out.push(C);
    }
  }
  return out;
}

function normalizeTrack(points, targetW, targetH, padding = 80) {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const [x, y] of points) {
    if (x < minX) minX = x;
    if (x > maxX) maxX = x;
    if (y < minY) minY = y;
    if (y > maxY) maxY = y;
  }
  const trackW = maxX - minX;
  const trackH = maxY - minY;
  const scale = Math.min(
    (targetW - padding * 2) / trackW,
    (targetH - padding * 2) / trackH
  );
  const offsetX = (targetW - trackW * scale) / 2 - minX * scale;
  const offsetY = (targetH - trackH * scale) / 2 - minY * scale;
  return points.map(([x, y]) => [x * scale + offsetX, y * scale + offsetY]);
}

// Precalcula spline, distancias acumuladas, anchuras variables y bordes
function preparedTrack(trackDef, samplesPerSeg = 5) {
  const smooth = catmullRomClosed(trackDef.points, samplesPerSeg);
  const n = smooth.length;

  const dists = [0];
  let total = 0;
  for (let i = 1; i < n; i++) {
    const dx = smooth[i][0] - smooth[i-1][0];
    const dy = smooth[i][1] - smooth[i-1][1];
    total += Math.sqrt(dx*dx + dy*dy);
    dists.push(total);
  }
  const dxC = smooth[0][0] - smooth[n-1][0];
  const dyC = smooth[0][1] - smooth[n-1][1];
  total += Math.sqrt(dxC*dxC + dyC*dyC);

  // Anchura variable basada en curvatura (estrecha — proporción auto/pista real)
  const MIN_W = 18, MAX_W = 18;  // 18m (1.5× ancho F1 real, más jugable)
  const rawWidths = new Float32Array(n);
  for (let i = 0; i < n; i++) {
    const prev = smooth[(i - 1 + n) % n];
    const next = smooth[(i + 1) % n];
    const a1 = Math.atan2(smooth[i][1] - prev[1], smooth[i][0] - prev[0]);
    const a2 = Math.atan2(next[1] - smooth[i][1], next[0] - smooth[i][0]);
    let da = Math.abs(a2 - a1);
    while (da > Math.PI) da = Math.abs(da - Math.PI * 2);
    const curv = Math.min(da / 0.085, 1);
    rawWidths[i] = MAX_W - curv * (MAX_W - MIN_W);
  }
  const widths = new Float32Array(n);
  const BLUR = 14;
  for (let i = 0; i < n; i++) {
    let sum = 0;
    for (let k = -BLUR; k <= BLUR; k++) sum += rawWidths[(i + k + n) % n];
    widths[i] = sum / (BLUR * 2 + 1);
  }

  const leftEdge  = [];
  const rightEdge = [];
  for (let i = 0; i < n; i++) {
    const prev = smooth[(i - 1 + n) % n];
    const next = smooth[(i + 1) % n];
    const ang = Math.atan2(next[1] - prev[1], next[0] - prev[0]);
    const nx = -Math.sin(ang);
    const ny =  Math.cos(ang);
    const hw = widths[i] * 0.5;
    leftEdge.push( [smooth[i][0] - nx * hw, smooth[i][1] - ny * hw]);
    rightEdge.push([smooth[i][0] + nx * hw, smooth[i][1] + ny * hw]);
  }

  return { def: trackDef, smooth, dists, total, widths, leftEdge, rightEdge };
}

// Línea de carrera (geométrica wide-apex-wide, suavizado gaussiano)
function computeRacingLine(track) {
  const smooth = track.smooth;
  const widths = track.widths;
  const n = smooth.length;

  const curv = new Float32Array(n);
  for (let i = 0; i < n; i++) {
    const prev = smooth[(i - 1 + n) % n];
    const curr = smooth[i];
    const next = smooth[(i + 1) % n];
    const a1 = Math.atan2(curr[1] - prev[1], curr[0] - prev[0]);
    const a2 = Math.atan2(next[1] - curr[1], next[0] - curr[0]);
    let da = a2 - a1;
    while (da >  Math.PI) da -= Math.PI * 2;
    while (da < -Math.PI) da += Math.PI * 2;
    curv[i] = da;
  }

  const rawOffset = new Float32Array(n);
  const LOOK = 25;
  for (let i = 0; i < n; i++) {
    let maxAbs = 0, sign = 0;
    for (let k = 0; k < LOOK; k++) {
      const c = curv[(i + k) % n];
      if (Math.abs(c) > maxAbs) { maxAbs = Math.abs(c); sign = Math.sign(c); }
    }
    rawOffset[i] = -sign * Math.min(maxAbs / 0.06, 1) * widths[i] * 0.32;
  }

  const offset = new Float32Array(n);
  const SIGMA = 20;
  const KERNEL_R = Math.ceil(SIGMA * 2.5);
  const kernel = [];
  let ksum = 0;
  for (let k = -KERNEL_R; k <= KERNEL_R; k++) {
    const v = Math.exp(-(k * k) / (2 * SIGMA * SIGMA));
    kernel.push(v);
    ksum += v;
  }
  for (let i = 0; i < n; i++) {
    let val = 0;
    for (let k = -KERNEL_R; k <= KERNEL_R; k++) {
      val += rawOffset[(i + k + n) % n] * kernel[k + KERNEL_R];
    }
    offset[i] = val / ksum;
  }

  const racingLine = [];
  for (let i = 0; i < n; i++) {
    const prev = smooth[(i - 1 + n) % n];
    const next = smooth[(i + 1) % n];
    const ang = Math.atan2(next[1] - prev[1], next[0] - prev[0]);
    const nx = -Math.sin(ang);
    const ny =  Math.cos(ang);
    racingLine.push([
      smooth[i][0] + nx * offset[i],
      smooth[i][1] + ny * offset[i],
    ]);
  }
  return racingLine;
}

